const NAV = ["Industries","Usecases","Platforms","Resources","About Us","Self-Serve"];

export default function Navbar() {
  return (
    <nav style={{
      position:"fixed",top:0,left:0,right:0,zIndex:1000,
      background:"rgba(255,255,255,0.97)",backdropFilter:"blur(10px)",
      borderBottom:"1px solid rgba(0,0,0,0.08)",
      height:64,padding:"0 40px",
      display:"flex",alignItems:"center",justifyContent:"space-between",
    }}>
      <div style={{display:"flex",alignItems:"center",gap:6}}>
        <div style={{
          width:38,height:38,borderRadius:"50%",
          border:"2.5px solid #e53e3e",
          display:"flex",alignItems:"center",justifyContent:"center",
          fontWeight:900,fontSize:12,color:"#e53e3e",letterSpacing:-0.5,
        }}>ID</div>
        <span style={{fontWeight:800,fontSize:20,color:"#1a1a1a",letterSpacing:-0.5}}>fy</span>
      </div>
      <div style={{display:"flex",alignItems:"center",gap:28}}>
        {NAV.map(l=>(
          <a key={l} href="#" style={{textDecoration:"none",color:"#374151",fontSize:14,fontWeight:500}}
            onMouseEnter={e=>e.target.style.color="#e53e3e"}
            onMouseLeave={e=>e.target.style.color="#374151"}>{l}</a>
        ))}
      </div>
      <div style={{display:"flex",gap:12}}>
        <button style={{
          background:"transparent",color:"#1a1a1a",border:"1.5px solid #1a1a1a",
          padding:"8px 22px",borderRadius:6,fontSize:14,fontWeight:600,cursor:"pointer",
        }}>Login</button>
        <button style={{
          background:"#e53e3e",color:"white",border:"none",
          padding:"8px 22px",borderRadius:6,fontSize:14,fontWeight:600,cursor:"pointer",
        }}>Book a Demo</button>
      </div>
    </nav>
  );
}
